import React from "react";
import { Link, useLocation } from "react-router-dom";
import { Home, Package, History, User, Activity } from "lucide-react";

function FooterB({ assignedOrderCount }) {
  const location = useLocation();
  const path = location.pathname;

  const navItems = [
    { label: "Home", path: "/delivery", icon: Home },
    { label: "Orders", path: "/delivery/orders", icon: Package, badge: assignedOrderCount },
    { label: "History", path: "/delivery/history", icon: History },
    { label: "Profile", path: "/delivery/proflle", icon: User },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 z-[100] px-4 pb-6 md:pb-8 pointer-events-none">
      <div className="max-w-md mx-auto pointer-events-auto">
        <nav className="bg-white/90 backdrop-blur-2xl border border-slate-200 rounded-[32px] shadow-2xl overflow-hidden px-4 py-3 flex items-center justify-between relative">
          
          {/* Active Status Indicator Shadow */}
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-teal-500/20 to-transparent" />

          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = path === item.path;
            
            return (
              <Link
                key={item.label}
                to={item.path}
                className={`relative flex flex-col items-center gap-1 group transition-all duration-300 ${
                  isActive ? "scale-110" : "opacity-60 hover:opacity-100"
                }`}
              >
                <div className={`p-2.5 rounded-2xl transition-all duration-500 ${
                    isActive 
                      ? "bg-teal-500 text-white shadow-lg shadow-teal-500/30" 
                      : "bg-slate-50 text-slate-400 group-hover:bg-slate-100 group-hover:text-slate-900"
                  }`}>
                  <Icon size={20} strokeWidth={isActive ? 2.5 : 2} />
                  
                  {/* Badge */}
                  {item.badge > 0 && (
                    <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-rose-500 text-[10px] font-black text-white border-2 border-white animate-in zoom-in shadow-sm">
                      {item.badge}
                    </span>
                  )}
                </div>
                
                <span className={`text-[10px] font-black uppercase tracking-widest transition-all duration-300 ${
                  isActive ? "text-teal-600" : "text-slate-500 group-hover:text-slate-700"
                }`}>
                  {item.label}
                </span>

                {/* Sub-dot for active state */}
                {isActive && (
                    <div className="w-1 h-1 rounded-full bg-teal-500 mt-0.5 animate-pulse" />
                )}
              </Link>
            );
          })}
        </nav>
      </div>

      <style>{`
        nav { font-family: 'Inter', sans-serif; }
      `}</style>
    </div>
  );
}

export default FooterB;
